#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100
#define INF 1000000

int main() {
    int T, n, m, i, j, k, l, temp, ans;
    int e[MAX], f[MAX], dist[MAX][MAX];
    int **graph;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        for (i = 0; i < n; i++) {
            scanf("%d", &e[i]);
            e[i]--;
        }
        for (i = 0; i < n; i++) {
            scanf("%d", &f[i]);
            f[i]--;
        }
        scanf("%d", &m);
        graph = (int **)malloc(n * sizeof(int *));
        for (i = 0; i < n; i++) {
            graph[i] = (int *)malloc(n * sizeof(int));
            for (j = 0; j < n; j++) {
                graph[i][j] = 0;
            }
        }
        for (i = 0; i < m; i++) {
            scanf("%d %d", &j, &k);
            j--; k--;
            graph[j][k] = graph[k][j] = 1;
        }
        for (i = 0; i < n; i++) {
            for (j = 0; j < n; j++) {
                dist[i][j] = INF;
            }
            dist[i][i] = 0;
        }
        for (i = 0; i < n; i++) {
            for (j = 0; j < n; j++) {
                for (k = 0; k < n; k++) {
                    if (dist[i][j] + graph[j][k] < dist[i][k]) {
                        dist[i][k] = dist[i][j] + graph[j][k];
                    }
                }
            }
        }
        ans = 0;
        for (i = 0; i < n; i++) {
            temp = INF;
            for (j = 0; j < n; j++) {
                if (j == e[i] || j == f[i]) {
                    temp = dist[i][j];
                    break;
                }
            }
            if (temp == INF) {
                printf("IMPOSSIBLE\n");
                goto next;
            }
            ans = ans > temp ? ans : temp;
        }
        printf("Case %d: %d\n", T - i, ans);
        next:
        continue;
    }
    return 0;
}

