    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] e = new int[n];
            int[] f = new int[n];
            for (int i = 0; i < n; i++) {
                e[i] = sc.nextInt() - 1;
            }
            for (int i = 0; i < n; i++) {
                f[i] = sc.nextInt() - 1;
            }
            int m = sc.nextInt();
            int[][] graph = new int[n][n];
            for (int i = 0; i < m; i++) {
                int j = sc.nextInt() - 1;
                int k = sc.nextInt() - 1;
                graph[j][k] = graph[k][j] = 1;
            }
            int[][] dist = new int[n][n];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    dist[i][j] = Integer.MAX_VALUE;
                }
                dist[i][i] = 0;
            }
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    for (int k = 0; k < n; k++) {
                        if (dist[i][j] + graph[j][k] < dist[i][k]) {
                            dist[i][k] = dist[i][j] + graph[j][k];
                        }
                    }
                }
            }
            int ans = 0;
            for (int i = 0; i < n; i++) {
                int temp = Integer.MAX_VALUE;
                for (int j = 0; j < n; j++) {
                    if (j == e[i] || j == f[i]) {
                        temp = dist[i][j];
                        break;
                    }
                }
                if (temp == Integer.MAX_VALUE) {
                    System.out.println("IMPOSSIBLE");
                    continue;
                }
                ans = Math.max(ans, temp);
            }
            System.out.println("Case " + (T + 1) + ": " + ans);
        }
    }
}

